  ('customs-7fec267e-moex-00236', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設A國的饅頭生產力為每小時生產1個饅頭，背心生產力為每小時生產1件背心；B國的饅頭生 產力為每小時生產3個饅頭，背心生產力為每小時生產2件背心。下列敘述何者正確？', '["對A國而言，生產1個饅頭的機會成本為1.5件背心", "對B國而言，生產1個饅頭的機會成本為1.5件背心", "對A國而言，生產1件背心的機會成本為1.5個饅頭", "對B國而言，生產1件背心的機會成本為1.5個饅頭"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
