  ('customs-7fec267e-moex-00238', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '在一個完全競爭市場中，市場供給函數為Q=P，市場需求函數為Q=20–P，其中P為商品價格而 Q則是商品數量。市場均衡時的生產者剩餘為何？', '["$10", "$25", "$50", "$100"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00239', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '南部水災造成水果減產，假設水果市場需求彈性小於1，則水果市場的：', '["生產者剩餘下降", "生產者剩餘上升", "均衡價格下降", "均衡交易量上升"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00240', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設某物品的反市場需求函數為p=100–2q，其中p為價格，q為數量。如果因為外在的因素（如所得提 高）使新的反市場需求函數變更為p’=120–2q，則當市場價格仍維持p=40固定不變時，需求彈性變動為：', '["1/6", "1/4", "1/3", "1/2"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00241', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '假設某國家的香水市場需求函數是qd=100–5p，其中p是價格，q是數量，而香水市場供給函數 是qs=–20+3p。假設政府對香水價格課徵百分之二十的貨物稅，則市場的均衡價格會增加多少？', '["1", "2", "3", "4"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00242', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '供給的短期價格彈性往往小於供給的長期價格彈性，這是：', '["因為消費者的消費行為與慣性在短期內不易調整，在長期較容易調整", "因為生產者在短期內不容易調整生產規模，在長期比較容易調整", "僅對於耐久財為真", "僅對於非耐久財為真"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00243', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '根據需求法則，下列敘述何者正確？', '["當一產品的價格上升時，其市場需求曲線會向左平移", "當一產品的價格下降時，其市場需求曲線會向右平移", "一產品的市場需求曲線為負斜率", "一產品的市場需求曲線為正斜率"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00244', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '亞當史密斯（AdamSmith）認為市場上有一隻看不見的手（aninvisiblehand）能夠調節供給和需求， 這隻看不見的手是指：', '["政府的政策", "價格機能", "供給者對於市場情勢的判斷", "消費者對於市場情勢的判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL),
  ('customs-7fec267e-moex-00245', 'customs-7fec267e', 'customs-7fec267e-moex-111-6948958a', 'sub-customs-7fec267e-01', NULL, 'single_choice', '商品A的市場需求函數為：Q =400–20P，市場供給函數為：Q =–20+10P。假設政府對商品A設 D S 置了供給上限80單位，則市場均衡的價格與數量分別是多少？', '["P=16,Q=80", "P=14,Q=120", "P=10,Q=80", "P=17,Q=60"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:22+00:00", "source_pdf_sha1": "9e4c296907e5", "answer_pdf_sha1": "4f3eb1fbbf91", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "141", "s": "0907", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "經濟學概要", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "一般行政"}'::jsonb, NULL)
